import sys
from typing import List

class Solution:
    def get_length_after_rotation(self, nums: List[int]) -> int:
        if not nums:
            return 0
        n = len(nums)
        for i in range(n-1, 0, -1):
            if nums[i] != nums[i-1]:
                break
        for j in range(i-1, -1, -1):
            if nums[j] != nums[j+1]:
                break
        return n - i

if __name__ == '__main__':
    T = int(input())
    nums = list(map(int, input().split()))
    s = Solution()
    print(s.get_length_after_rotation(nums))

