#include <iostream>
#include <vector>

using namespace std;
class Solution {
public:
int getLengthAfterRotation(vector<int>& nums) {
    if (!nums.size()) return 0;
    int n = nums.size(), i = n-1, j = n-1;
    while (i > 0 && nums[i] == nums[i-1]) i--;
    while (j > 0 && nums[j] == nums[j-1]) j--;
    return n - i;
};
};

int main() {
    int T; cin >> T;
    vector<int> nums(T);
    for (int i = 0; i < T; i++) {
        cin >> nums[i];
    }
    Solution s;
    cout << s.getLengthAfterRotation(nums);
    return 0;
}
